                'data' => '{"pages":[{"num":1,"text":"Hari ini ulang tahun Dina. Ia sangat gembira."},{"num":2,"text":"Ibu memberinya kado cantik dalam kotak merah."},{"num":3,"text":"Dina sangat penasaran dan ingin segera membukanya."},{"num":4,"text":"Tapi ia melihat anak tetangga yang sedang menangis."},{"num":5,"text":"Anak itu tidak mendapat kado ulang tahun karena ibunya sakit."},{"num":6,"text":"Dina merasa iba. Ia ingin membantu."},{"num":7,"text":"Ia membuka kadonya. Di dalamnya ada boneka cantik."},{"num":8,"text":"Dina sangat menyukai boneka itu. Tapi ia berpikir."},{"num":9,"text":"Dina menghampiri anak itu dan memberikan bonekanya."},{"num":10,"text":"Anak itu berhenti menangis dan tersenyum."},{"num":11,"text":"Dina merasa bahagia melihat anak itu gembira."},{"num":12,"text":"Ia belajar bahwa ikhlas memberi lebih berharga daripada menerima."},{"num":13,"text":"Ibu memeluk Dina dengan bangga."},{"num":14,"text":"Dina mengajak teman-temannya berbagi hadiah dengan yang kurang beruntung."},{"num":15,"text":"Sejak itu, Dina selalu ikhlas berbagi."}]}',
