                'data' => '{"pages":[{"num":1,"text":"Sinta adalah pelari tercepat di sekolahnya. Ia selalu menang."},{"num":2,"text":"Hari ini ada lomba lari antar kelas. Sinta sangat siap."},{"num":3,"text":"Ia ingin sekali memenangkan piala juara untuk kelasnya."},{"num":4,"text":"Lomba dimulai. Sinta berlari sangat cepat."},{"num":5,"text":"Ia hampir mencapai garis finish. Semua bersorak."},{"num":6,"text":"Tiba-tiba teman di sampingnya terjatuh."},{"num":7,"text":"Sinta berhenti. Ia membantu temannya bangkit."},{"num":8,"text":"Teman lainnya finish lebih dulu. Sinta kehilangan juara."},{"num":9,"text":"Tapi Sinta tidak menyesal. Ia tersenyum."},{"num":10,"text":"Temannya mengucapkan terima kasih. Sinta bahagia."},{"num":11,"text":"Guru memuji Sinta atas ketulusannya."},{"num":12,"text":"Sinta belajar bahwa ikhlas lebih penting daripada menang."},{"num":13,"text":"Ia merelakan piala itu demi pertolongan."},{"num":14,"text":"Sinta mengajak teman-teman untuk saling membantu."},{"num":15,"text":"Sejak itu, Sinta ikhlas meskipun tidak selalu menang."}]}',
                'desc' => 'Sinta merelakan kemenangannya setelah melihat temannya lebih membutuhkan.',
