                'data' => '{"pages":[{"num":1,"text":"Bayu memiliki mainan robot kesayangan. Ia sangat menyukainya."},{"num":2,"text":"Ia bermain robot itu setiap hari. Robot itu sangat keren."},{"num":3,"text":"Adiknya, Lia, juga ingin bermain dengan robot itu."},{"num":4,"text":"Bayu tidak mau memberikan robotnya. Ia takut rusak."},{"num":5,"text":"Lia menangis karena tidak diajak bermain."},{"num":6,"text":"Bayu melihat Lia menangis. Ia merasa kasihan."},{"num":7,"text":"Ia berpikir, Haruskah aku memberikan robot ini?"},{"num":8,"text":"Bayu menghampiri Lia dan memberikan robotnya."},{"num":9,"text":"Lia berhenti menangis dan tersenyum bahagia."},{"num":10,"text":"Bayu melihat Lia bermain. Hatinya terharu."},{"num":11,"text":"Ia merasa bahagia meskipun kehilangan mainan."},{"num":12,"text":"Bayu belajar bahwa ikhlas berbagi membuat keluarga harmonis."},{"num":13,"text":"Ibu memeluk Bayu karena kebaikannya."},{"num":14,"text":"Bayu mengajak Lia bermain bersama."},{"num":15,"text":"Sejak itu, Bayu ikhlas berbagi dengan adiknya."}]}',
