                'data' => '{"pages":[{"num":1,"text":"Mega memiliki kebun bunga kecil di halaman rumahnya."},{"num":2,"text":"Ia menanam bunga-bunga itu dengan penuh cinta."},{"num":3,"text":"Bunga-bunga itu mekar sangat indah. Mega bangga."},{"num":4,"text":"Suatu hari, ibu Mega terlihat lelah dan sedih."},{"num":5,"text":"Mega ingin membuat ibunya tersenyum."},{"num":6,"text":"Ia melihat bunga-bunga di kebunnya."},{"num":7,"text":"Mega memetik bunga-bunga itu meskipun berat."},{"num":8,"text":"Ia merangkai bunga menjadi buket yang cantik."},{"num":9,"text":"Mega memberikan buket itu pada ibunya."},{"num":10,"text":"Ibu terkejut dan tersenyum bahagia."},{"num":11,"text":"Mega sangat senang melihat ibunya bahagia."},{"num":12,"text":"Ia belajar bahwa ikhlas memberi membuat hati orang lain senang."},{"num":13,"text":"Ibu memeluk Mega dengan erat."},{"num":14,"text":"Mega mengajak adiknya merawat kebun bunga bersama."},{"num":15,"text":"Sejak itu, Mega ikhlas memberikan bunganya untuk orang yang dicintai."}]}',
