                'creator' => 'copilot',
                'data' => '{"pages":[{"num":1,"text":"Dina berkunjung ke taman kota."},{"num":2,"text":"Kereta mini berputar mengelilingi taman."},{"num":3,"text":"Dina sangat ingin menaikinya."},{"num":4,"text":"Antrean ternyata sangat panjang."},{"num":5,"text":"Beberapa anak mulai tidak sabar."},{"num":6,"text":"Dina berdiri rapi di barisan."},{"num":7,"text":"Giliran Dina masih lama."},{"num":8,"text":"Petugas taman menyapanya ramah."},{"num":9,"text":"Petugas berterima kasih karena Dina tertib."},{"num":10,"text":"Dina terus menunggu dengan tenang."},{"num":11,"text":"Akhirnya ia mendapat giliran naik."},{"num":12,"text":"Dina mengerti arti menghargai giliran."},{"num":13,"text":"Perjalanannya terasa sangat menyenangkan."},{"num":14,"text":"Ia mengajak teman tetap antre."},{"num":15,"text":"Mereka pulang dengan hati riang."}]}',
