                'data' => '{"pages":[{"num":1,"text":"Gajah muda hidup di hutan lebat."},{"num":2,"text":"Ia sering bermain dekat sungai."},{"num":3,"text":"Ia ingin memakan buah di seberang."},{"num":4,"text":"Arus sungai sedang sangat deras."},{"num":5,"text":"Batu-batu penyeberangan tertutup air."},{"num":6,"text":"Gajah mencari jalan lain."},{"num":7,"text":"Semua jalur masih sulit dilalui."},{"num":8,"text":"Seekor rusa tua datang."},{"num":9,"text":"Rusa berkata arus segera mengecil."},{"num":10,"text":"Gajah menunggu dengan sabar."},{"num":11,"text":"Sore hari air menjadi tenang."},{"num":12,"text":"Ia memahami pentingnya menanti keadaan baik."},{"num":13,"text":"Buah manis berhasil dinikmatinya."},{"num":14,"text":"Ia mengajak teman memperhatikan alam."},{"num":15,"text":"Hutan terasa damai menjelang malam."}]}',
