                'data' => '{"pages":[{"num":1,"text":"Budi membantu paman di toko roti."},{"num":2,"text":"Pagi itu adonan sedang dibuat."},{"num":3,"text":"Budi ingin segera mencicipi roti."},{"num":4,"text":"Roti belum matang di tungku."},{"num":5,"text":"Harumnya membuat Budi semakin penasaran."},{"num":6,"text":"Ia membuka tungku sedikit."},{"num":7,"text":"Roti masih belum siap dimakan."},{"num":8,"text":"Paman tersenyum melihatnya."},{"num":9,"text":"Paman menjelaskan roti perlu waktu matang."},{"num":10,"text":"Budi menunggu sambil membantu toko."},{"num":11,"text":"Roti hangat akhirnya siap."},{"num":12,"text":"Budi mengerti pentingnya proses."},{"num":13,"text":"Rasanya sangat lezat dan lembut."},{"num":14,"text":"Ia mengajak sepupunya bersabar juga."},{"num":15,"text":"Toko roti penuh aroma bahagia."}]}',
                'desc' => 'Aroma roti dan cerita keluarga berpadu dalam kisah penuh kesabaran.',
                'id' => 64,
