                'data' => '{"pages":[{"num":1,"text":"Kura-kura tua tinggal di pantai."},{"num":2,"text":"Setiap malam ia melihat mercusuar."},{"num":3,"text":"Ia ingin menuju pulau kecil."},{"num":4,"text":"Lampu mercusuar belum menyala."},{"num":5,"text":"Arah laut sulit dikenali."},{"num":6,"text":"Kura-kura mulai berjalan perlahan."},{"num":7,"text":"Ia berhenti karena masih ragu."},{"num":8,"text":"Seekor lumba-lumba muncul dari laut."},{"num":9,"text":"Lumba-lumba menyarankan menunggu lampu menyala."},{"num":10,"text":"Kura-kura menunggu dengan tenang."},{"num":11,"text":"Lampu biru menyala terang."},{"num":12,"text":"Ia mengerti manfaat kesabaran."},{"num":13,"text":"Perjalanan berjalan lancar."},{"num":14,"text":"Ia membagikan pengalaman kepada hewan lain."},{"num":15,"text":"Pantai malam terasa hangat dan aman."}]}',
                'desc' => 'Perjalanan pantai yang menunjukkan bahwa langkah tenang dapat membawa hasil baik.',
                'id' => 65,
