                'agama' => '[]',
                'ages' => '[5,6,7,8]',
                'created_by' => 1,
                'creator' => 'deepseek',
                'data' => '{"pages":[{"num":1,"text":"Sinta sedang berjalan pulang dari sekolah."},{"num":2,"text":"Ia melihat uang kertas tergeletak di jalan."},{"num":3,"text":"Sinta sangat senang. Ia bisa membeli mainan impiannya."},{"num":4,"text":"Tapi ia berpikir, Ini uang siapa ya?"},{"num":5,"text":"Sinta melihat sekitar, tidak ada siapa-siapa."},{"num":6,"text":"Ia hampir memasukkan uang itu ke tasnya."},{"num":7,"text":"Tapi hatinya tidak tenang."},{"num":8,"text":"Sinta melihat teman sekelasnya menangis."},{"num":9,"text":"Temannya kehilangan uang jajan."},{"num":10,"text":"Sinta bertanya, Berapa uang yang hilang?"},{"num":11,"text":"Temannya menyebutkan jumlah yang sama."},{"num":12,"text":"Sinta mengembalikan uang itu. Ini uangmu."},{"num":13,"text":"Temannya sangat berterima kasih."},{"num":14,"text":"Sinta mengajak teman lain untuk selalu jujur."},{"num":15,"text":"Sejak itu, Sinta selalu mengembalikan barang yang ditemukan."}]}',
                'desc' => 'Sinta mengembalikan uang temannya meskipun ia sangat menginginkannya.',
                'id' => 69,
                'image' => 'cover.png',
                'moral' => 'Kejujuran adalah pilihan untuk tetap benar meskipun tidak ada yang melihat. Sinta menemukan uang di jalan dan sangat ingin membeli mainan, tetapi ia sadar bahwa uang itu milik orang lain. Ia memilih untuk mencari pemiliknya dan mengembalikan uang itu dengan ikhlas. Meskipun ia tidak jadi membeli mainan, kebahagiaan melihat temannya yang kehilangan uang tersenyum karena uangnya kembali membuat Sinta merasa lebih kaya. Sinta belajar bahwa kejujuran adalah harta yang tidak bisa dicuri dan membuat kita menjadi pribadi yang lebih baik dan dipercaya oleh banyak orang.',
                'notes' => NULL,
                'plans' => NULL,
                'prompt' => NULL,
                'skills' => '["jujur"]',
