                'data' => '{"pages":[{"num":1,"text":"Di kelas, guru bertanya pada Mega tentang matematika."},{"num":2,"text":"Mega tidak tahu jawabannya."},{"num":3,"text":"Ia melihat teman-temannya menunggu jawabannya."},{"num":4,"text":"Mega ingin menjawab asal saja agar tidak malu."},{"num":5,"text":"Tapi ia ragu. Itu tidak jujur."},{"num":6,"text":"Temannya berbisik, Coba jawab saja."},{"num":7,"text":"Mega mengambil napas panjang."},{"num":8,"text":"Maaf, Bu. Saya tidak tahu jawabannya, kata Mega."},{"num":9,"text":"Semua teman diam. Mega takut diejek."},{"num":10,"text":"Guru tersenyum. Terima kasih sudah jujur, Mega."},{"num":11,"text":"Guru kemudian menjelaskan jawabannya."},{"num":12,"text":"Mega belajar bahwa jujur lebih baik daripada berbohong."},{"num":13,"text":"Ia merasa tenang setelah berkata jujur."},{"num":14,"text":"Mega mengajak temannya untuk berani berkata jujur."},{"num":15,"text":"Sejak itu, Mega selalu jujur tentang apa yang ia ketahui."}]}',
