                'data' => '{"pages":[{"num":1,"text":"Di dekat sungai, hiduplah seekor kucing kecil yang lapar."},{"num":2,"text":"Ia melihat ikan asin di rumah tetangga."},{"num":3,"text":"Kucing kecil sangat ingin memakannya."},{"num":4,"text":"Ia mencuri satu ikan dan memakannya."},{"num":5,"text":"Setelah kenyang, kucing kecil merasa bersalah."},{"num":6,"text":"Ia tidak bisa tidur. Hatinya gelisah."},{"num":7,"text":"Kucing kecil menangis karena menyesal."},{"num":8,"text":"Esoknya, ia pergi ke rumah tetangga."},{"num":9,"text":"Maaf, aku mencuri ikannya, kata kucing kecil."},{"num":10,"text":"Tetangga tersenyum. Kamu jujur, aku maafkan."},{"num":11,"text":"Tetangga memberi kucing kecil satu ikan lagi."},{"num":12,"text":"Kucing kecil belajar bahwa kejujuran membawa kebaikan."},{"num":13,"text":"Ia merasa sangat bahagia dan lega."},{"num":14,"text":"Kucing kecil mengajak hewan lain untuk selalu jujur."},{"num":15,"text":"Sejak itu, kucing kecil tidak pernah mencuri lagi."}]}',
