            [
                'active' => 1,
                'addon_id' => NULL,
                'agama' => '[]',
                'ages' => '[5,6,7,8,9]',
                'created_by' => 1,
                'creator' => 'copilot',
                'data' => '{"pages":[{"num":1,"text":"Bayu tinggal dekat pasar kota."},{"num":2,"text":"Ia senang mengumpulkan mainan."},{"num":3,"text":"Bayu ingin mendapat hadiah baru."},{"num":4,"text":"Hadiah itu diberikan kepada orang lain."},{"num":5,"text":"Bayu merasa kecewa."},{"num":6,"text":"Ia membantu ayah di pasar."},{"num":7,"text":"Perasaannya belum sepenuhnya hilang."},{"num":8,"text":"Seorang pedagang berbincang dengannya."},{"num":9,"text":"Pedagang bercerita tentang ketulusan."},{"num":10,"text":"Bayu mencoba menerima keadaan."},{"num":11,"text":"Ia berhasil membantu banyak orang."},{"num":12,"text":"Bayu memahami arti ikhlas."},{"num":13,"text":"Ia merasa lebih bahagia."},{"num":14,"text":"Ia mengajak teman berbagi kebaikan."},{"num":15,"text":"Mereka pulang dengan hati hangat."}]}',
                'desc' => 'Petualangan keluarga yang menunjukkan bahwa kebahagiaan sejati datang dari hati yang tulus.',
                'id' => 86,
                'image' => 'cover.png',
                'moral' => 'Keikhlasan membuat kita menyadari bahwa kebahagiaan tidak selalu berasal dari hadiah atau benda. Saat kita membantu, berbagi, dan menerima keadaan dengan hati terbuka, kita menemukan kebahagiaan yang lebih dalam. Sikap ikhlas menumbuhkan rasa syukur, kepedulian, dan ketenangan dalam kehidupan sehari-hari.',
                'notes' => NULL,
                'plans' => NULL,
                'prompt' => NULL,
                'skills' => '["ikhlas"]',
                'slug' => 'bayu-menemukan-kebahagiaan-yang-tidak-dibungkus',
