                'data' => '{"pages":[{"num":1,"text":"Bayu suka bermain kelereng di lapangan."},{"num":2,"text":"Ia bermain bersama teman-temannya."},{"num":3,"text":"Bayu ingin memiliki kelereng unik."},{"num":4,"text":"Ia menemukan kelereng bercahaya."},{"num":5,"text":"Tidak ada yang tahu pemiliknya."},{"num":6,"text":"Bayu menyimpannya sementara."},{"num":7,"text":"Hatinya masih ragu."},{"num":8,"text":"Temannya Rudi datang mencarinya."},{"num":9,"text":"Bayu belajar pentingnya kejujuran."},{"num":10,"text":"Ia mengaku menemukan kelereng itu."},{"num":11,"text":"Kelereng kembali kepada pemiliknya."},{"num":12,"text":"Bayu mengerti arti jujur."},{"num":13,"text":"Ia merasa lega."},{"num":14,"text":"Teman-teman ikut berlaku jujur."},{"num":15,"text":"Mereka bermain dengan gembira."}]}',
                'desc' => 'Kisah menarik tentang anak yang memilih berkata jujur meski godaan sangat besar.',
