                'data' => '{"pages":[{"num":1,"text":"Rina belajar rajin di sekolah."},{"num":2,"text":"Hari itu guru membagikan hasil tugas."},{"num":3,"text":"Rina ingin mendapat nilai baik."},{"num":4,"text":"Nilainya terlihat sangat tinggi."},{"num":5,"text":"Ia merasa ada yang aneh."},{"num":6,"text":"Rina memeriksa kembali tugasnya."},{"num":7,"text":"Ternyata nilainya tertukar."},{"num":8,"text":"Guru lewat di dekat meja."},{"num":9,"text":"Rina belajar berkata terus terang."},{"num":10,"text":"Ia memberi tahu gurunya."},{"num":11,"text":"Kesalahan nilai diperbaiki."},{"num":12,"text":"Rina memahami kejujuran."},{"num":13,"text":"Hatinya tenang."},{"num":14,"text":"Teman-teman menghargainya."},{"num":15,"text":"Kelas menjadi lebih percaya satu sama lain."}]}',
                'desc' => 'Cerita sekolah yang menunjukkan keberanian untuk mengatakan yang sebenarnya.',
