                'data' => '{"pages":[{"num":1,"text":"Andi senang membaca buku."},{"num":2,"text":"Ia sering ke perpustakaan."},{"num":3,"text":"Andi ingin memiliki pensil bagus."},{"num":4,"text":"Ia menemukan pensil baru."},{"num":5,"text":"Pensil itu tertinggal di meja."},{"num":6,"text":"Andi mengambilnya."},{"num":7,"text":"Ia bimbang membawanya pulang."},{"num":8,"text":"Petugas perpustakaan menyapanya."},{"num":9,"text":"Andi belajar untuk jujur."},{"num":10,"text":"Ia menyerahkan pensil itu."},{"num":11,"text":"Pemiliknya sangat bersyukur."},{"num":12,"text":"Andi memahami nilai kejujuran."},{"num":13,"text":"Ia tersenyum lega."},{"num":14,"text":"Temannya ikut meniru."},{"num":15,"text":"Perpustakaan terasa lebih ramah."}]}',
