                'agama' => '[]',
                'ages' => '[4,5,6,7]',
                'created_by' => 1,
                'creator' => 'deepseek',
                'data' => '{"pages":[{"num":1,"text":"Di hutan, hiduplah gajah besar yang sombong."},{"num":2,"text":"Ia selalu meremehkan hewan-hewan kecil."},{"num":3,"text":"Kau terlalu kecil, tidak bisa apa-apa, katanya pada semut."},{"num":4,"text":"Semut tidak marah. Ia tetap tersenyum."},{"num":5,"text":"Suatu hari, gajah terjebak dalam lubang besar."},{"num":6,"text":"Ia berteriak minta tolong. Tidak ada yang bisa menolong."},{"num":7,"text":"Semut kecil mendengar teriakan gajah."},{"num":8,"text":"Semut memanggil semua teman semutnya."},{"num":9,"text":"Mereka membuat tali dari daun dan menarik gajah."},{"num":10,"text":"Akhirnya gajah berhasil keluar."},{"num":11,"text":"Gajah malu. Terima kasih, semut. Kau hebat."},{"num":12,"text":"Gajah belajar bahwa semua makhluk istimewa."},{"num":13,"text":"Ia tidak pernah meremehkan hewan kecil lagi."},{"num":14,"text":"Gajah mengajak semua hewan bermain bersama."},{"num":15,"text":"Sejak itu, gajah menjadi hewan yang rendah hati."}]}',
                'desc' => 'Gajah besar belajar untuk tidak meremehkan makhluk kecil setelah ditolong oleh semut.',
                'id' => 118,
                'image' => 'cover.png',
                'moral' => 'Rendah hati adalah kemampuan untuk menghargai semua makhluk tanpa melihat ukuran atau kekuatan mereka. Gajah besar awalnya meremehkan semut karena ia merasa lebih besar dan lebih kuat. Namun, ketika gajah terjebak dalam lubang dan tidak bisa keluar, semut kecil datang membantu dengan memanggil teman-temannya. Gajah belajar bahwa setiap makhluk memiliki kelebihan dan kekurangan masing-masing. Ia tidak boleh sombong hanya karena tubuhnya besar. Rendah hati membuat kita belajar dari siapa pun dan tidak pernah menganggap remeh orang lain.',
                'notes' => NULL,
                'plans' => NULL,
                'prompt' => NULL,
                'skills' => '["rendah_hati"]',
