                'created_by' => 1,
                'creator' => 'deepseek',
                'data' => '{"pages":[{"num":1,"text":"Dina mendapat gaun baru dari ibunya. Gaun itu sangat cantik."},{"num":2,"text":"Ia ingin segera memakainya ke sekolah."},{"num":3,"text":"Dina membayangkan teman-temannya akan memuji."},{"num":4,"text":"Tapi ia melihat temannya yang tidak punya gaun bagus."},{"num":5,"text":"Dina jadi berpikir."},{"num":6,"text":"Ia tidak mau membuat temannya merasa sedih."},{"num":7,"text":"Dina memakai gaun sederhana ke sekolah."},{"num":8,"text":"Temannya bertanya, Kenapa tidak pakai gaun baru?"},{"num":9,"text":"Aku tidak mau pamer, kata Dina."},{"num":10,"text":"Temannya tersenyum dan memeluk Dina."},{"num":11,"text":"Dina bahagia bisa menjaga perasaan teman."},{"num":12,"text":"Ia belajar bahwa rendah hati membuat semua orang nyaman."},{"num":13,"text":"Ia memakai gaun barunya hanya pada acara keluarga."},{"num":14,"text":"Dina mengajak temannya berbagi kebahagiaan sederhana."},{"num":15,"text":"Sejak itu, Dina tidak pernah memamerkan barang-barangnya."}]}',
