            ],
            [
                'active' => 1,
                'addon_id' => NULL,
                'agama' => '[]',
                'ages' => '[7,8,9,10]',
                'created_by' => 1,
                'creator' => 'glm52',
                'data' => '{"pages":[{"num":1,"text":"Putri adalah seorang gadis di desa danau. Ia memiliki gaun putih berkilau yang dihiasi ratusan batu kristal."},{"num":2,"text":"Ia selalu memakainya berjalan ke pasar agar semua orang mengagumi pakaian yang sangat berkilau itu."},{"num":3,"text":"Suatu hari, Putri ingin pergi ke hutan untuk memetik buah. Ia tetap memakai gaun berkilauan kesayangannya."},{"num":4,"text":"Cahaya matahari memantul dari gaunnya. Pantulan itu sangat menyilaukan, membuat matanya sendiri menjadi sakit."},{"num":5,"text":"Putri tidak bisa melihat jalan setapak. Ia tersesat jauh ke dalam hutan yang gelap dan lebat."},{"num":6,"text":"Ia berjalan tersandung akar. Gaunnya robek dahan duri. Putri duduk di atas batu menangis kelelahan."},{"num":7,"text":"Penduduk hutan lewat, tapi mereka buta karena silau gaunnya. Tidak ada yang berani mendekat untuk menolongnya."},{"num":8,"text":"Seorang anak gembala sederhana datang membawa selimut. Ia menutupi gaun itu agar tidak memantulkan cahaya."},{"num":9,"text":"Anak gembala itu memandu Putri keluar dari hutan. Putri tersadar bahwa gaun kesombongannya yang membahayakannya."},{"num":10,"text":"Keesokan harinya, Putri melepas gaun kristalnya. Ia memakai pakaian sederhana dan keluar berbaur dengan warga."},{"num":11,"text":"Tanpa gaun menyilaukan, semua orang bisa melihat senyumnya. Banyak teman yang datang menyapa dan mengajaknya bermain."},{"num":12,"text":"Putri sangat bahagia. Ia mengerti bahwa keindahan sejati adalah kerendahan hati yang membuat orang merasa nyaman di dekat kita."},{"num":13,"text":"Putri menyimpan gaunnya di dalam lemari. Ia tidak lagi ingin menjadi pusat perhatian yang menyilaukan mata tetangganya."},{"num":14,"text":"Ia mengajak anak-anak desa bermain di danau. Mereka tertawa lepas tanpa ada jarak antara Putri dan teman-temannya."},{"num":15,"text":"Desa danau menjadi hangat. Putri belajar bahwa kesederhanaan dan kerendahan hati adalah gaun terindah yang pernah ada."}]}',
                'desc' => 'Putri bangga dengan gaun berkilauannya hingga cahayanya menyilaukan dan membuatnya tersesat di hutan.',
                'id' => 179,
                'image' => 'cover.png',
                'moral' => 'Rendah hati adalah tidak berlebihan dalam menunjukkan apa yang kita miliki. Memamerkan kekayaan atau kepandaian justru bisa mengganggu orang lain dan menyesatkan diri sendiri. Anak yang merendah hati akan tampil sederhana, sehingga cahaya kebaikan di hatinya yang akan terlihat oleh orang lain tanpa harus menyilaukan mata.',
                'notes' => NULL,
                'plans' => NULL,
                'prompt' => NULL,
                'skills' => '["rendah_hati"]',
                'slug' => 'putri-danau-dan-gaun-berkilau-yang-menyilaukan',
