                'data' => '{"pages":[{"num":1,"text":"Bayu senang bermain di lapangan desa."},{"num":2,"text":"Temannya memiliki kebiasaan berbeda-beda."},{"num":3,"text":"Bayu ingin semua bermain bersama."},{"num":4,"text":"Anak-anak membentuk kelompok sendiri."},{"num":5,"text":"Mereka jarang bermain bersama."},{"num":6,"text":"Bayu mengajak mereka berkumpul."},{"num":7,"text":"Ajakan itu belum berhasil."},{"num":8,"text":"Guru datang ke lapangan."},{"num":9,"text":"Guru mengajarkan menghargai perbedaan."},{"num":10,"text":"Bayu mencoba mengajak lagi."},{"num":11,"text":"Semua anak mau bermain bersama."},{"num":12,"text":"Bayu mengerti arti toleransi."},{"num":13,"text":"Permainan menjadi sangat seru."},{"num":14,"text":"Mereka mengajak teman lain."},{"num":15,"text":"Lapangan penuh tawa ceria."}]}',
                'desc' => 'Cerita hangat tentang anak yang belajar menerima perbedaan teman-temannya.',
