                'data' => '{"pages":[{"num":1,"text":"Kura-kura tua tinggal di pantai."},{"num":2,"text":"Ia sering dibantu teman."},{"num":3,"text":"Ia ingin menyenangkan mereka."},{"num":4,"text":"Ia sering lupa berterima kasih."},{"num":5,"text":"Temannya kecewa."},{"num":6,"text":"Kura-kura berusaha berubah."},{"num":7,"text":"Ia masih sering lupa."},{"num":8,"text":"Lumba-lumba menasihatinya."},{"num":9,"text":"Ia belajar menghargai bantuan."},{"num":10,"text":"Kura-kura membiasakan diri."},{"num":11,"text":"Teman-teman senang."},{"num":12,"text":"Ia memahami sopan santun."},{"num":13,"text":"Persahabatan makin erat."},{"num":14,"text":"Mereka saling membantu."},{"num":15,"text":"Pantai terasa hangat."}]}',
