                'creator' => 'copilot',
                'data' => '{"pages":[{"num":1,"text":"Budi sering bermain di taman."},{"num":2,"text":"Taman selalu bersih."},{"num":3,"text":"Ia ingin tahu rahasianya."},{"num":4,"text":"Banyak anak mengabaikan penjaga."},{"num":5,"text":"Pak penjaga tetap bekerja."},{"num":6,"text":"Budi menyapanya ramah."},{"num":7,"text":"Anak lain belum peduli."},{"num":8,"text":"Pak penjaga bercerita."},{"num":9,"text":"Budi belajar menghargai orang."},{"num":10,"text":"Ia mengajak teman menyapa."},{"num":11,"text":"Pak penjaga tersenyum."},{"num":12,"text":"Budi memahami sopan."},{"num":13,"text":"Taman terasa akrab."},{"num":14,"text":"Anak-anak ikut menghormati."},{"num":15,"text":"Semua merasa bahagia."}]}',
