                'agama' => '[]',
                'ages' => '[5,6,7,8,9]',
                'created_by' => 1,
                'creator' => 'copilot',
                'data' => '{"pages":[{"num":1,"text":"Bayu suka berjalan pagi."},{"num":2,"text":"Ia bertemu banyak orang."},{"num":3,"text":"Ia ingin menyebarkan kebaikan."},{"num":4,"text":"Sebagian orang tampak murung."},{"num":5,"text":"Suasana kurang ceria."},{"num":6,"text":"Bayu memberi salam pagi."},{"num":7,"text":"Perubahan belum terlihat."},{"num":8,"text":"Kakek tetangga menyemangati."},{"num":9,"text":"Bayu belajar konsisten bersikap sopan."},{"num":10,"text":"Ia terus menyapa ramah."},{"num":11,"text":"Banyak orang tersenyum kembali."},{"num":12,"text":"Bayu memahami arti sopan."},{"num":13,"text":"Lingkungan menjadi ceria."},{"num":14,"text":"Semua saling menyapa."},{"num":15,"text":"Pagi terasa sangat hangat."}]}',
                'desc' => 'Kisah penutup yang menunjukkan bahwa kesopanan membawa banyak kebaikan.',
                'id' => 246,
                'image' => 'cover.png',
                'moral' => 'Kesopanan adalah kebiasaan baik yang dapat dipraktikkan setiap hari. Dengan menyapa, menghormati, mendengarkan, dan berbicara dengan baik, kita dapat membuat orang lain merasa dihargai serta menciptakan suasana yang penuh kebahagiaan dan persahabatan.',
                'notes' => NULL,
                'plans' => NULL,
                'prompt' => NULL,
                'skills' => '[]',
                'slug' => 'mengapa-semua-menyukai-salam-pagi-bayu',
