            ],
            [
                'active' => 1,
                'addon_id' => NULL,
                'agama' => '[]',
                'ages' => '[5,6,7,8]',
                'created_by' => 1,
                'creator' => NULL,
                'data' => '{"pages":[{"num":1,"text":"Rina memiliki teman baru bernama Sari. Sari berasal dari desa yang jauh."},{"num":2,"text":"Sari memiliki kebiasaan yang berbeda. Ia makan dengan tangan kanan."},{"num":3,"text":"Rina heran. Ia biasa makan dengan sendok dan garpu."},{"num":4,"text":"Rina merasa Sari aneh. Ia menjauhinya."},{"num":5,"text":"Sari sedih karena Rina tidak mau berteman dengannya."},{"num":6,"text":"Ibu Rina melihat sikap Rina. Kenapa kau menjauhi Sari?"},{"num":7,"text":"Ia berbeda, Bu. Aku tidak terbiasa, kata Rina."},{"num":8,"text":"Ibu tersenyum. Perbedaan itu indah, Nak."},{"num":9,"text":"Rina merenung. Ia mulai berpikir."},{"num":10,"text":"Rina menghampiri Sari dan mengajaknya bermain."},{"num":11,"text":"Mereka bermain bersama dengan gembira."},{"num":12,"text":"Rina belajar bahwa perbedaan bukanlah penghalang persahabatan."},{"num":13,"text":"Ia bahagia bisa berteman dengan Sari."},{"num":14,"text":"Rina mengajak teman lain untuk menerima Sari."},{"num":15,"text":"Sejak itu, Rina selalu menghargai perbedaan teman-temannya."}]}',
                'desc' => 'Rina belajar menerima teman baru yang memiliki kebiasaan berbeda darinya.',
                'id' => 247,
                'image' => 'cover.png',
                'moral' => 'Toleransi adalah kemampuan untuk menerima dan menghargai perbedaan yang ada di sekitar kita. Rina awalnya merasa asing dengan teman barunya yang memiliki kebiasaan berbeda dalam makan dan bermain. Namun, ia belajar bahwa perbedaan bukanlah halangan untuk berteman. Ia mulai memahami bahwa setiap orang memiliki cara hidup yang berbeda-beda dan itu adalah hal yang wajar. Dengan toleransi, Rina menemukan bahwa perbedaan justru membuat persahabatan menjadi lebih kaya dan penuh warna. Kita tidak harus sama untuk bisa saling menyayangi dan menghormati satu sama lain.',
                'notes' => NULL,
                'plans' => NULL,
                'prompt' => NULL,
                'skills' => '[]',
                'slug' => 'rina-dan-teman-baru-yang-berbeda-kebiasaan',
                'sort_order' => 0,
                'status' => 'pending',
                'title' => 'Rina dan Teman Baru yang Berbeda Kebiasaan',
                'type' => 'storytelling',
                'views' => 0,
            ],
            [
                'active' => 1,
                'addon_id' => NULL,
                'agama' => '[]',
                'ages' => '[4,5,6,7]',
                'created_by' => 1,
                'creator' => NULL,
                'data' => '{"pages":[{"num":1,"text":"Di taman yang indah, hiduplah burung merak dengan bulu cantik."},{"num":2,"text":"Ia selalu memamerkan keindahannya. Ia merasa paling hebat."},{"num":3,"text":"Burung gereja datang dan ingin berteman."},{"num":4,"text":"Burung merak menolak. Kau terlalu biasa untukku."},{"num":5,"text":"Burung gereja sedih dan pergi."},{"num":6,"text":"Suatu hari, burung merak terjebak dalam jaring."},{"num":7,"text":"Ia berteriak minta tolong. Tidak ada yang datang."},{"num":8,"text":"Burung gereja mendengar dan datang menolong."},{"num":9,"text":"Ia mematuk jaring dengan paruhnya."},{"num":10,"text":"Akhirnya burung merak bebas."},{"num":11,"text":"Burung merak malu. Maafkan aku, teman."},{"num":12,"text":"Burung merak belajar bahwa semua makhluk istimewa."},{"num":13,"text":"Mereka berteman dan saling melengkapi."},{"num":14,"text":"Burung merak mengajak semua burung berteman."},{"num":15,"text":"Sejak itu, mereka hidup rukun dan toleran."}]}',
                'desc' => 'Burung merak yang cantik berteman dengan burung gereja yang sederhana dan belajar toleransi.',
                'id' => 248,
                'image' => 'cover.png',
                'moral' => 'Toleransi mengajarkan bahwa kecantikan sejati terletak pada kemampuan untuk menerima perbedaan. Burung merak sangat cantik dengan bulu-bulunya yang indah, sementara burung gereja sederhana dan tidak menarik perhatian. Awalnya burung merak merasa lebih hebat dan tidak mau berteman. Namun, ia belajar bahwa setiap makhluk memiliki keindahan dan keistimewaannya masing-masing. Burung gereja memiliki suara yang merdu dan hati yang baik. Dengan toleransi, mereka menjadi sahabat yang saling melengkapi. Kita tidak harus sama untuk bisa saling menghargai dan menyayangi.',
                'notes' => NULL,
                'plans' => NULL,
                'prompt' => NULL,
                'skills' => '[]',
                'slug' => 'mengapa-burung-merak-berteman-dengan-burung-gereja',
                'sort_order' => 0,
                'status' => 'pending',
                'title' => 'Mengapa Burung Merak Berteman dengan Burung Gereja?',
                'type' => 'storytelling',
                'views' => 0,
            ],
            [
                'active' => 1,
                'addon_id' => NULL,
                'agama' => '[]',
                'ages' => '[4,5,6,7]',
                'created_by' => 1,
                'creator' => NULL,
                'data' => '{"pages":[{"num":1,"text":"Bayu bermain di taman. Ia membawa mobil-mobilan kesayangannya."},{"num":2,"text":"Temannya, Dina, membawa boneka cantik."},{"num":3,"text":"Bayu tidak suka boneka. Itu mainan perempuan, katanya."},{"num":4,"text":"Dina sedih mendengar itu."},{"num":5,"text":"Bayu terus bermain sendiri."},{"num":6,"text":"Tapi ia melihat Dina bermain dengan gembira."},{"num":7,"text":"Bayu jadi penasaran."},{"num":8,"text":"Ia menghampiri Dina. Boleh aku main?"},{"num":9,"text":"Dina tersenyum. Tentu saja."},{"num":10,"text":"Bayu bermain boneka dan ternyata menyenangkan."},{"num":11,"text":"Mereka bermain bersama dengan gembira."},{"num":12,"text":"Bayu belajar bahwa semua mainan itu menyenangkan."},{"num":13,"text":"Ia bahagia bisa bermain dengan Dina."},{"num":14,"text":"Bayu mengajak teman lain bermain bersama."},{"num":15,"text":"Sejak itu, Bayu menghargai mainan teman-temannya."}]}',
                'desc' => 'Bayu belajar bermain dengan teman yang memiliki mainan berbeda dan menghargainya.',
                'id' => 249,
                'image' => 'cover.png',
                'moral' => 'Toleransi adalah kemampuan untuk menghargai pilihan dan kesukaan orang lain meskipun berbeda dengan kita. Bayu suka bermain mobil-mobilan, sedangkan temannya suka bermain boneka. Awalnya Bayu menganggap mainan boneka itu membosankan. Namun, ketika ia mencoba memainkannya, ia menemukan bahwa boneka juga menyenangkan. Bayu belajar bahwa perbedaan adalah hal yang wajar dan kita bisa belajar banyak hal dari orang lain. Dengan toleransi, kita bisa menemukan teman baru dan pengalaman baru yang menyenangkan. Dunia menjadi lebih indah ketika kita saling menghargai.',
                'notes' => NULL,
                'plans' => NULL,
                'prompt' => NULL,
                'skills' => '[]',
                'slug' => 'bayu-dan-mainan-yang-berbeda-di-taman',
                'sort_order' => 0,
                'status' => 'pending',
                'title' => 'Bayu dan Mainan yang Berbeda di Taman',
                'type' => 'storytelling',
                'views' => 0,
            ],
            [
                'active' => 1,
                'addon_id' => NULL,
                'agama' => '["islam"]',
                'ages' => '[6,7,8,9]',
                'created_by' => 1,
                'creator' => NULL,
                'data' => '{"pages":[{"num":1,"text":"Sinta merayakan Idul Fitri bersama keluarga. Semua gembira."},{"num":2,"text":"Temannya, Maria, merayakan Natal."},{"num":3,"text":"Sinta heran. Apa itu Natal?"},{"num":4,"text":"Ia bertanya pada ibunya."},{"num":5,"text":"Ibu menjelaskan bahwa semua orang punya hari raya sendiri."},{"num":6,"text":"Sinta ingin mengucapkan selamat pada Maria."},{"num":7,"text":"Ia pergi ke rumah Maria."},{"num":8,"text":"Selamat Natal, Maria, kata Sinta."},{"num":9,"text":"Maria tersenyum. Terima kasih, Sinta."},{"num":10,"text":"Mereka bermain bersama dengan gembira."},{"num":11,"text":"Sinta belajar bahwa perbedaan itu indah."},{"num":12,"text":"Ia menghormati hari raya temannya."},{"num":13,"text":"Sinta bahagia bisa berteman dengan Maria."},{"num":14,"text":"Sinta mengajak teman lain menghormati perbedaan."},{"num":15,"text":"Sejak itu, Sinta selalu toleran pada teman yang berbeda."}]}',
                'desc' => 'Sinta belajar menghormati hari raya temannya yang berbeda keyakinan.',
                'id' => 250,
                'image' => 'cover.png',
                'moral' => 'Toleransi beragama adalah sikap mulia yang mengajarkan kita untuk menghormati keyakinan orang lain. Sinta dan keluarganya merayakan hari raya Idul Fitri dengan penuh sukacita. Ketika temannya merayakan Natal, Sinta merasa asing dan bingung. Namun, ia belajar bahwa setiap orang memiliki cara yang berbeda untuk merayakan kebahagiaan. Sinta mengucapkan selamat kepada temannya dan ikut bergembira. Ia belajar bahwa perbedaan keyakinan tidak mengurangi rasa persahabatan. Toleransi beragama membuat kita hidup rukun dan damai meskipun berbeda keyakinan.',
                'notes' => NULL,
                'plans' => NULL,
                'prompt' => NULL,
                'skills' => '[]',
                'slug' => 'sinta-dan-hari-raya-yang-berbeda',
