                'agama' => '[]',
                'ages' => '[6,7,8,9]',
                'created_by' => 1,
                'creator' => NULL,
                'data' => '{"pages":[{"num":1,"text":"Mega mendapat teman baru bernama Joko dari Jawa."},{"num":2,"text":"Joko berbicara dengan bahasa Jawa."},{"num":3,"text":"Mega tidak mengerti bahasa Jawa. Ia bingung."},{"num":4,"text":"Mega menjauhi Joko karena tidak bisa berkomunikasi."},{"num":5,"text":"Joko sedih dan merasa dikucilkan."},{"num":6,"text":"Ibu Mega melihat sikap Mega."},{"num":7,"text":"Bahasa adalah kekayaan, Nak. Belajarlah menghargai."},{"num":8,"text":"Mega merenung dan menyesal."},{"num":9,"text":"Ia belajar beberapa kata bahasa Jawa."},{"num":10,"text":"Mega menghampiri Joko. Ayo berteman!"},{"num":11,"text":"Joko tersenyum bahagia."},{"num":12,"text":"Mega belajar bahwa perbedaan bahasa itu indah."},{"num":13,"text":"Mereka saling belajar bahasa masing-masing."},{"num":14,"text":"Mega mengajak teman lain belajar bahasa daerah."},{"num":15,"text":"Sejak itu, Mega menghargai semua bahasa."}]}',
                'desc' => 'Mega belajar memahami teman yang berbicara dengan bahasa daerah yang berbeda.',
                'id' => 252,
                'image' => 'cover.png',
                'moral' => 'Toleransi bahasa mengajarkan bahwa bahasa adalah kekayaan budaya yang harus dihargai. Mega bingung ketika teman barunya berbicara dengan bahasa daerah yang tidak ia mengerti. Ia hampir menjauhi teman itu karena merasa tidak nyaman. Namun, ibunya mengajarkan bahwa perbedaan bahasa adalah hal yang wajar dan kita bisa belajar untuk saling memahami. Mega mencoba belajar beberapa kata dari bahasa temannya dan temannya pun belajar bahasa Indonesia. Mereka menjadi sahabat yang saling belajar dan menghargai perbedaan.',
                'notes' => NULL,
                'plans' => NULL,
                'prompt' => NULL,
                'skills' => '[]',
                'slug' => 'mega-dan-bahasa-yang-berbeda',
                'sort_order' => 0,
