            [
                'active' => 1,
                'addon_id' => NULL,
                'agama' => '[]',
                'ages' => '[5,6,7,8]',
                'created_by' => 1,
                'creator' => NULL,
                'data' => '{"pages":[{"num":1,"text":"Andi suka mendengarkan lagu pop di radio."},{"num":2,"text":"Temannya, Lina, suka lagu daerah."},{"num":3,"text":"Lina memutar lagu daerah di kelas."},{"num":4,"text":"Andi bosan. Lagu itu kuno, katanya."},{"num":5,"text":"Lina sedih mendengar itu."},{"num":6,"text":"Guru mendengar dan menjelaskan makna lagu daerah."},{"num":7,"text":"Andi jadi penasaran."},{"num":8,"text":"Ia mendengarkan lagu itu dengan saksama."},{"num":9,"text":"Ternyata lagu itu indah dan bermakna."},{"num":10,"text":"Andi minta maaf. Maaf, aku tidak tahu."},{"num":11,"text":"Mereka menyanyikan lagu itu bersama."},{"num":12,"text":"Andi belajar bahwa semua lagu itu indah."},{"num":13,"text":"Ia bahagia bisa mendengar lagu baru."},{"num":14,"text":"Andi mengajak teman lain mendengarkan lagu daerah."},{"num":15,"text":"Sejak itu, Andi menghargai semua jenis musik."}]}',
                'desc' => 'Andi belajar menyukai lagu daerah yang berbeda dari yang biasa ia dengar.',
                'id' => 253,
                'image' => 'cover.png',
